<?php require_once '../config/db.php'; require_once '../includes/auth.php'; require_admin(); $page_title='Membership Plans'; if(isset($_GET['delete'])){mysqli_query($conn,'DELETE FROM MEMBERSHIP_PLAN WHERE plan_id='.intval($_GET['delete'])); header('Location: plans.php'); exit();} if($_SERVER['REQUEST_METHOD']==='POST'){ $stmt=mysqli_prepare($conn,'INSERT INTO MEMBERSHIP_PLAN(plan_name,duration_months,monthly_fee,plan_type,description) VALUES(?,?,?,?,?)'); mysqli_stmt_bind_param($stmt,'sidss',$_POST['plan_name'],$_POST['duration_months'],$_POST['monthly_fee'],$_POST['plan_type'],$_POST['description']); mysqli_stmt_execute($stmt); header('Location: plans.php'); exit(); } $result=mysqli_query($conn,'SELECT * FROM MEMBERSHIP_PLAN ORDER BY plan_id DESC'); require_once '../includes/header.php'; require_once '../includes/sidebar.php'; ?>
<div class="card form-card"><h2>Add Plan</h2><form method="POST" class="form-grid"><div><label>Plan Name</label><input class="input" name="plan_name" required></div><div><label>Duration Months</label><input class="input" type="number" name="duration_months" required></div><div><label>Monthly Fee</label><input class="input" type="number" step="0.01" name="monthly_fee" required></div><div><label>Type</label><select name="plan_type"><option>Basic</option><option>Standard</option><option>Premium</option><option>Student</option><option>Personal Training</option></select></div><div class="full"><label>Description</label><textarea name="description"></textarea></div><div class="full"><button class="btn">Add Plan</button></div></form></div><h2 class="section-title">Plans</h2><div class="table-wrap"><table><tr><th>ID</th><th>Name</th><th>Duration</th><th>Fee</th><th>Type</th><th>Description</th><th>Action</th></tr><?php while($r=mysqli_fetch_assoc($result)): ?><tr><td><?= safe($r['plan_id']) ?></td><td><?= safe($r['plan_name']) ?></td><td><?= safe($r['duration_months']) ?></td><td><?= safe($r['monthly_fee']) ?></td><td><?= safe($r['plan_type']) ?></td><td><?= safe($r['description']) ?></td><td><a class="btn btn-danger" onclick="return confirm('Delete plan?')" href="plans.php?delete=<?= $r['plan_id'] ?>">Delete</a></td></tr><?php endwhile; ?></table></div><?php require_once '../includes/footer.php'; ?>
